INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 1, 2834, 8, "青空の下で謁見", 91002, 10118, "ペコリーヌとの出会い", 5118061, 2, 7, "フリーマーケット会場", 0, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 40);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 1, 2835, 8, "未来の騎空団\nマスコット？", 91002, 10118, "マホとの出会い", 5118062, 2, 7, "フリーマーケット会場", 0, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 40);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 1, 2837, 8, "お嬢さまからの\n緊急依頼", 91002, 10118, "アキノとの出会い", 5118063, 2, 7, "ランドソル市街地", 0, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 40);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 1, 4108402, 8, "黄金色の悩みごと", 91002, 10118, "ジュンとの出会い", 5118064, 2, 18, "フリーマーケット会場", 0, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 40);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 1, 4107402, 8, "白熱！　格闘大会！", 91002, 10118, "カオリとの出会い", 5118065, 2, 18, "フリーマーケット会場", 0, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 40);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 1, 9000227, 8, "祭り太鼓はオーエドの華", 91002, 10118, "ニノンとの出会い", 5118066, 2, 16, "オーエド町", 1, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 40);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 1, 2101181, 8, "人気者は遅れて\nやってくる", 91002, 10118, "スズナとの出会い", 5118067, 3, 19, "フリーマーケット会場", 0, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 40);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 1, 4109402, 8, "巫女・ミーツ・魔法少女", 91002, 10118, "ナナカとの出会い", 5118068, 3, 18, "ランドソル市街地", 0, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 40);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 1, 4305402, 8, "ネズ耳は二度なくなる", 91002, 10118, "キャル＆コッコロとの出会い", 5118069, 3, 18, "フリーマーケット会場", 0, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 40);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 1, 4101402, 8, "この出会いにカンパイ！", 91002, 10118, "ユカリとの出会い", 5118070, 3, 18, "ランドソル市街地", 0, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 40);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 1, 4106402, 8, "陰陽アンサンブル", 91002, 10118, "アオイとの出会い", 5118071, 3, 18, "ランドソル市街地", 0, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 40);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 1, 2836, 8, "運試し十番勝負！", 91002, 10118, "シノブとの出会い", 5118072, 3, 7, "フリーマーケット会場", 1, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 40);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (20063115, 0, 0, 0, "彼女たちの新たな日常", 0, 10118, "オープニング", 5118600, 1, 0, 0, 0, 0, 0);
